body:
Is this supposed to work?  Or am I doing something incorrectly?

``` js
'use strict';

var excel = require('exceljs');

var testFilepath = 'path/to/some/file.xlsx';
var wb1 = new excel.Workbook();
var wb2 = new excel.Workbook();

wb1.creator = 'Me';
wb1.lastModifiedBy = 'Her';
wb1.created = new Date(1985, 8, 30);
wb1.modified = new Date();
wb1.addWorksheet('test');

wb1.xlsx.writeFile(testFilepath)
    .then(function() {
        return wb2.xlsx.readFile(testFilepath);
    })
    .then(function() {
        console.log(wb2);
        /*
        OUTPUT:

        { created: undefined,
          modified: undefined,
          _worksheets:
           [ ,
             { id: 1,
               name: 'test',
               _rows: [],
               _columns: null,
               _keys: {},
               _merges: {},
               _workbook: [Circular],
               tabColor: undefined,
               dataValidations: [Object] } ],
          _definedNames: { matrixMap: {} },
          _xlsx: { workbook: [Circular] },
          creator: undefined,
          lastModifiedBy: undefined }
          */
    });
```

Notice that `creator`, `created`, etc. are `undefined`.  The documentation says column "metadata" is not persisted, but it doesn't say the same for these workbook values.  Using `exceljs@0.2.7` in Linux environment.
